import React from "react";

const BarraHorizontal = ({
  texto,
  height = "clamp(2vh, 3.82vh, 5vh)", // Mucho más delgada usando proporción áurea menor
  margenHorizontal = "clamp(5vw, 10vw, 15vw)",
  imagen,
}) => {
  const containerStyle = { height };

  const imageStyle = {
    backgroundImage: `url(${imagen})`,
    width: margenHorizontal,
  };

  return (
    <div 
      style={containerStyle} 
      className="w-full flex items-center overflow-hidden bg-surface border-y border-stroke shadow-sm"
    >
      <div
        style={imageStyle}
        className="bg-repeat-x bg-center h-[60%] flex-shrink-0 bg-[length:auto_100%] opacity-70"
      />
      <div
        className="flex-grow h-full flex items-center justify-center font-bodoni text-black text-xs md:text-sm lg:text-base xl:text-lg tracking-wider transform -translate-y-[2%] font-bold uppercase px-2 md:px-4"
      >
        {texto}
      </div>
      <div
        style={imageStyle}
        className="bg-repeat-x bg-center h-[60%] flex-shrink-0 bg-[length:auto_100%] opacity-70"
      />
    </div>
  );
};

export default BarraHorizontal;
